export interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60; // for exactly 3 alike components
const PROCESSING_FEE = 5;

// Modifiers
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_THRESHOLD = 2;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FOLLOW_UP_DISCOUNT = 0.15;

function getBasePremium(item: Item): number {
  if (item.type in BASE_PREMIUMS) {
    return BASE_PREMIUMS[item.type];
  }

  // Check if it's a component type (anything not in BASE_PREMIUMS)
  if (!Object.keys(BASE_PREMIUMS).includes(item.type)) {
    // It's a component
    return COMPONENT_BASE_PREMIUM;
  }

  throw new Error(`Unknown item type: ${item.type}`);
}

function isComponent(type: string): boolean {
  return !Object.keys(BASE_PREMIUMS).includes(type);
}

function groupComponents(items: Item[]): Map<string, Item[]> {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    if (isComponent(item.type)) {
      if (!groups.has(item.type)) {
        groups.set(item.type, []);
      }
      groups.get(item.type)!.push(item);
    }
  }
  return groups;
}

function calculateComponentBasePremium(items: Item[]): number {
  const groups = groupComponents(items);
  let total = 0;

  for (const [, groupItems] of groups) {
    // Check if exactly 3 components of same type (block)
    if (groupItems.length === 3) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else if (groupItems.length % 3 === 0 && groupItems.length > 3) {
      // Multiple blocks
      const numBlocks = Math.floor(groupItems.length / 3);
      const remainder = groupItems.length % 3;
      total += numBlocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
    } else {
      // No block
      total += groupItems.length * COMPONENT_BASE_PREMIUM;
    }
  }

  return total;
}

export function calculateQuote(
  customer: Customer,
  items: Item[],
  isFollowUp: boolean = false
): number {
  // Validate items
  for (const item of items) {
    if (!Object.keys(BASE_PREMIUMS).includes(item.type) && !isComponent(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  // Calculate base premiums
  let basePremium = 0;

  // Add non-component items base premium with item-specific modifiers
  for (const item of items) {
    if (!isComponent(item.type)) {
      let itemPremium = getBasePremium(item);

      // Apply item-specific modifiers
      if (item.cursed) {
        itemPremium += itemPremium * CURSE_SURCHARGE;
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemPremium += itemPremium * HIGH_ENCHANTMENT_SURCHARGE;
      }

      basePremium += itemPremium;
    }
  }

  // Add components base premium (with block logic)
  basePremium += calculateComponentBasePremium(items);

  // Apply policy-wide modifiers
  let premium = basePremium;

  // First insurance surcharge (applies to new policies or new items)
  premium += basePremium * FIRST_INSURANCE_SURCHARGE;

  // Loyalty discount (policy-wide)
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD) {
    premium -= basePremium * LOYALTY_DISCOUNT;
  }

  // Follow-up contract discount (policy-wide)
  if (isFollowUp) {
    premium -= basePremium * FOLLOW_UP_DISCOUNT;
  }

  // Processing fee
  premium += PROCESSING_FEE;

  // Round in the MHPCO's favor (up)
  return Math.ceil(premium);
}

